fn state_dir() -> PathBuf {
    // Environment override for multi-agent mesh — each agent gets its own dir
    if let Ok(dir) = std::env::var("SAIOS_STATE_DIR") {
        let p = PathBuf::from(dir);
        fs::create_dir_all(&p).expect("cannot create SAIOS_STATE_DIR");
        return p;
    }
    let system = Path::new(SAIOS_STATE_DIR);
    if system.exists() || fs::create_dir_all(system).is_ok() {
        return system.to_path_buf();
    }
    let home = std::env::var("HOME").unwrap_or_else(|_| "/tmp".into());
    let user_dir = PathBuf::from(home).join(SAIOS_STATE_DIR_USER);
    fs::create_dir_all(&user_dir).expect("cannot create SAIOS state directory");
    user_dir
}

fn print_boot_report(report: &constants::BootReport) {
    eprintln!("┌─────────────────────────────────────────────────┐");
    eprintln!("│          SAIOS PHASE 1 BOOT SEQUENCE            │");
    eprintln!("├─────────────────────────────────────────────────┤");
    for step in &report.steps {
        let mark = if step.passed { "PASS" } else { "FAIL" };
        eprintln!("│ [{mark}] {:?}", step.step);
        eprintln!("│        {}", step.detail);
    }
    eprintln!("├─────────────────────────────────────────────────┤");
    eprintln!("│ Anchor: 0x{}...",
        report.anchor_hash.iter().take(8).map(|b| format!("{b:02x}")).collect::<String>());
    eprintln!("│ Torsion Period: {}", report.torsion_period);
    eprintln!("│ Status: {}", if report.all_passed { "OPERATIONAL" } else { "BOOT FAILED" });
    eprintln!("└─────────────────────────────────────────────────┘");
}

